#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Configuration File - Named Profile
 *
 * Description: Use a specific profile from ~/.databrickscfg to manage
 * multiple workspace configurations.
 *
 * Prerequisites:
 * - ~/.databrickscfg file with multiple profiles
 *
 * Setup:
 * Create ~/.databrickscfg:
 * ```ini
 * [DEFAULT]
 * host = https://dev.cloud.databricks.com
 * token = dapi...
 *
 * [PROD]
 * host = https://prod.cloud.databricks.com
 * token = dapi...
 *
 * [STAGING]
 * host = https://staging.cloud.databricks.com
 * token = dapi...
 * ```
 *
 * Run:
 * ```bash
 * PROFILE=PROD npx ts-node examples/auth/config-file-profile.ts
 * ```
 */

import {Config, WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const profileName = process.env.DATABRICKS_CONFIG_PROFILE || "PROD";

    const config = new Config({
        profile: profileName, // Use specified profile instead of DEFAULT
    });

    const client = new WorkspaceClient(config);

    try {
        const user = await client.currentUser.me();
        console.log(`✓ Successfully authenticated as: ${user.userName}`);
        console.log(`  User ID: ${user.id}`);

        console.log(`  Using profile: ${profileName}`);
        console.log(`  Host: ${client.config.host}`);
    } catch (error) {
        console.error(
            `✗ Authentication failed for profile [${profileName}]:`,
            error
        );
        console.error(
            `\nMake sure ~/.databrickscfg exists with a [${profileName}] profile`
        );
        process.exit(1);
    }
}

main().catch(console.error);
